var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"이 떨거지들이......! 선수를 방해해도 된다니까 죽일 듯이 달려들어?","JPN":"雑魚どもが……！　選手の妨害がOKだからって殺す気で飛び掛かってくるの！？","ENG":"Those gnats... They're supposed to interfere with the runners, not kill them!","TWN":"你們這些小嘍囉……！雖然規則是妨礙，你們還真不要命了？"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"그리고 왜 나만 노리는 거야! 다른 녀석들도 많은데!","JPN":"なんで私ばっかり狙うの！　他のやつもいるのに！","ENG":"And why are they all after me and not somebody else?","TWN":"不過幹嘛只盯著我啊！還有那麼多人呢！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"이건 분명 감정 섞인 공격이야! 경기 끝나고 두고 봐!","JPN":"これは間違いなく私情が入った攻撃よ！　試合が終わったら全員まとめて覚悟しなさい！","ENG":"This has to be personal! I'll make them pay after the game!","TWN":"這分明是蓄意攻擊！等比賽結束要你們好看！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_BLUE","text":{"KOREA":"미, 미안해요......!","JPN":"ご、ごめんなさい……！","ENG":"I-I'm sorry!","TWN":"對，對不起……！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_BLUE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_BLUE","text":{"KOREA":"이야앗!!","JPN":"やああっ！！","ENG":"Eeyaaap!","TWN":"咿呀啊！！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_BLUE","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"히이익-!","JPN":"ひいいーっ！","ENG":"Heeek!","TWN":"（驚）咿！！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"PLAYER_SPORTS_NPC_BLUE","text":{"KOREA":"죄송합니다! 선배님!","JPN":"ごめんなさい！　先輩！","ENG":"I'm sorry, Naielle!","TWN":"抱歉，前輩！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"흐히이익?!","JPN":"ひいいいーっ！？","ENG":"Heeek!","TWN":"呃嘿咿咿？！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_SHOTGUN_FIRE_SMALL"},{"id":"L19_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"방금 건 분명 죽었어! 맞았으면 진짜로 죽었다고!!","JPN":"今のは確実に死ぬところだったわよ！？　リアルに当たると死ぬやつよそれ！？","ENG":"That was a killing blow! I would have died if that hit!","TWN":"剛才分明應該死了！打中了就是死了呀！！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"너희들! 죄송하다면서 왜 계속 머리를 노리는 거야?!","JPN":"あんたたち！　ごめんなさいと言いながら私の頭ばかり狙うのはやめて！？","ENG":"You! If you're so sorry, why do you keep aiming at my head?","TWN":"你們！嘴裡說著對不起，卻一直盯著我的頭？！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HARIM_REBBIT_SPORTS_BG","text":{"KOREA":"홍팀의 나이엘 블루스틸 선수! 선두를 달리며 마지막 바퀴에 진입합니다!","JPN":"赤組のナイエル・ブルースチール選手！　先頭を走りながら最後の一周に入ります！","ENG":"Naielle Bluesteel of the Red Team, on the last lap before everyone else!","TWN":"紅隊的奈爾選手！一馬當先地進入最後一圈了！"},"stage":{"bg":"SS_SPORTS_02","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L24_1","type":"dialog","speaker":"HARIM_REBBIT_SPORTS_BG","text":{"KOREA":"청팀의 방해가 거세지만, 이대로 가면 1등은 확정 같아 보이네요!","JPN":"青組の妨害が激しいものの、この調子だと1位は確定ですね！","ENG":"The Blue Team is trying really hard to stop her, but at this rate, it's obvious she'll come in first.","TWN":"雖然藍隊的阻礙很激烈，但不出意外，第一名應該是奈爾沒錯了！"},"stage":{"bg":"SS_SPORTS_02","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"흐, 흥! 그럼 그렇지!","JPN":"ふ、ふん！　当たり前よ！","ENG":"H-hmpf! I knew it!","TWN":"呵，哼！我就說嘛！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_PRIDE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"떨거지들이 아무리 방해해 봤자 떨거지들이지!","JPN":"雑魚はどうあがいても雑魚だから！","ENG":"Gnats are gnats, no matter how hard they try to be something else!","TWN":"小嘍囉們再怎麼妨礙都無濟於事！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"흐음, 그럼 탐색전은 끝난 것 같고......","JPN":"ふうん、様子見はこの程度にして……","ENG":"Hmm, I guess I'm done observing the situation.","TWN":"哼嗯，試探性的對戰看來也差不多了……"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"슬슬 스퍼트를 올려 볼까?","JPN":"そろそろスパートをかけようかな？","ENG":"It's time to pick up the pace.","TWN":"提升一下速度吧？"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"......응?","JPN":"……うん？","ENG":"Huh?","TWN":"……嗯？"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_PRIDE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"히익! 뭐, 뭐야! 저거! 뭐 저렇게 빨라!","JPN":"ひぃっ！　な、なにアレ？　なんであんなに速いの？","ENG":"Heeek! W-what the heck? How can she be so fast?","TWN":"哎呀！什、什麼！那個！她怎麼會那麼快！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_BLUE","text":{"KOREA":"저 언니, 엄청 강하다......! 순식간에 앞서 나가기 시작했어!","JPN":"あのお姉さん、すごく強い……！　あっという間に追い越した！","ENG":"Oh, she's incredible! She closed the distance almost at once!","TWN":"那個姐姐，非常強……！瞬間就領先了！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_BLUE","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_BLUE","face":"UNIT_SURPRISE"}}}},{"id":"L38_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_BLUE","text":{"KOREA":"저것 봐! 홍팀이 방해해도 염력만 갖고 가볍게 튕겨내잖아!","JPN":"あれを見て！　赤組が邪魔しても念動力だけで軽く弾いたよ！","ENG":"Look at that. She's using her telekinesis to fend off the Red Team's attacks!","TWN":"快看！她只用念力就輕巧地彈開了紅隊的妨礙！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_BLUE","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_BLUE","face":"UNIT_SURPRISE"}}}},{"id":"L39_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_BLUE","text":{"KOREA":"꼭 Z-맨의 마그네틱 교수 같아!","JPN":"まるでZ-MANのマグネティック教授みたい！","ENG":"She's like Magnetic from the Z-Men!","TWN":"就好像X-MAN裡的萬磁王一樣！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_BLUE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_BLUE","face":"UNIT_SURPRISE"}}}},{"id":"L40_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_BLUE","text":{"KOREA":"응...... 정말 화려해. 꼭 카운터가 되기 위해 태어난 사람 같아.","JPN":"うん……本当にかっこいいね。まるでカウンターになるために生まれた人みたい。","ENG":"Yes... She's amazing. It's as if she was born to be a Counter.","TWN":"嗯……真是太酷了。就像是天生的制裁者。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_BLUE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_BLUE","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"HARIM_REBBIT_SPORTS_BG","text":{"KOREA":"마지막으로 달리던 청팀의 서윤 선수! 순식간에 나이엘 선수의 뒤를 바짝 쫓아옵니다!","JPN":"最後尾を走っていた青組のアオイ・シズカ選手！　瞬く間にナイエル選手の後ろに迫っています！","ENG":"Seo Yoon of the Blue Team, who's been trailing the pack! She's suddenly gaining distance on Naielle!","TWN":"後發制人的藍隊徐芸選手！瞬間就超過了奈爾選手！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_SPORTS_BG","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"HARIM_REBBIT_SPORTS_BG","text":{"KOREA":"과연! 따라잡을 수 있을 것인가?!","JPN":"果たして！　追いつけるのでしょうか！？","ENG":"Let's see if she can catch up!","TWN":"究竟！能不能追上呢？！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_SPORTS_BG","face":"UNIT_LAUGH"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"이, 이건 불공평해! 엘리트인 내가 그렇게 달리기 연습을 했는데 이딴 식으로 쉽게 따라잡힌다고?","JPN":"こ、こんなのおかしいわよ！　ズルしてるんじゃない？\\nエリートの私があれだけ練習したのにこんな簡単に追いつかれるなんて！？","ENG":"Th-this is not fair! I'm an elite, and I've been practicing so hard! How can she catch up with me so easily?","TWN":"這，這不公平！身為精英的我那麼努力地練習跑步，竟然以這種方式被超越？"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_SERIOUS"}}}},{"id":"L48_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"카운터라면 달리기 연습보단 능력을 갈고 닦아서 응용할 줄 알아야지.","JPN":"カウンターなら走る練習より、自分の能力を磨いて応用しないとね。","ENG":"You should have practiced using your Counter ability instead of running.","TWN":"身為制裁者，比起練習賽跑，更要懂得練就本事。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_SERIOUS"}}}},{"id":"L49_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"아, 학교만 다니는 <color=#ffd34c>아. 마. 추. 어.</color> 씨라 그런 건 아직 어려우려나?","JPN":"あ、学校しか経験していない<color=#ffd34c>ア・マ・チュ・ア</color>さんだからそんなことはまだ無理かしら？","ENG":"Oh, was it too challenging for an <color=#ffd34c>A. M. A. T. E. U. R.</color> who's still in school?","TWN":"啊，對於只知道上學的<color=#ffd34c>業.餘.</color>選手來說這個可能有點難？"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"이이이익!! 다들 뭘 구경만 하는 거야!","JPN":"んもおぉぉぉ！！　みんな何をみてるの！","ENG":"Grrr! What are you doing, guys?","TWN":"咿咿咿啊！！你們愣著幹什麼！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"어그로! 블로킹! 뭐 해! <color=#ffd34c>그걸</color> 써서 막아!","JPN":"アグロ！　ブロッキング！　何やってんの！　<color=#ffd34c>あれ</color>を使って止めて！","ENG":"Aggro! Block! Come on! Use <color=#ffd34c>that</color> to stop her!","TWN":"阿格洛！布洛京！愣著幹什麼！快用<color=#ffd34c>那個</color>擋住她！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"지금이야! 나이엘이 승부수를 띄웠어!","JPN":"今だ！　ナイエルが勝負に出た！","ENG":"Our time has come! Naielle is using the ace up her sleeve!","TWN":"就是現在！奈爾要一決勝負了！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"STUDENT_EXTRA_B_TWINTAIL","text":{"KOREA":"과연! 어디선가 구해 온 고장 난 라이노를 고쳐 두라던 명령은 이 순간을 위해서였군!","JPN":"さすが！　どっかで拾ってきた壊れたライノを直しておけという命令は、この瞬間のためだったんだな！","ENG":"I know! This is why she wanted us to fix that broken Rhino that she found!","TWN":"原來！讓我修理不知道從哪兒弄來壞掉的犀牛就是為了這一刻！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_22"},{"id":"L9_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"좋아! 이걸로 청팀 선수의 길을 막는다!","JPN":"よし！　これで青組選手の道を塞ぐ！","ENG":"Alright, let's use it to stop that Blue Team player!","TWN":"好！就用這個擋住藍隊選手吧！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"STUDENT_EXTRA_B_TWINTAIL","text":{"KOREA":"이거라면 나이엘의 승리는 확정적이지!","JPN":"これを使えばナイエルの勝利は決まりだ！","ENG":"It'll ensure Naielle's victory!","TWN":"有了這個，奈爾就能穩贏了！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"저건......?","JPN":"あれは……？","ENG":"What's that?","TWN":"那是……？"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"아하하하하!","JPN":"アハハハハ！","ENG":"Ah hah hah hah hah!","TWN":"啊哈哈哈哈！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"어때?! 대회를 위해 구해둔 공성 전차라고!","JPN":"どう！？　大会のために入手した攻城戦車よ！","ENG":"Behold the siege tank that I've prepared for this competition!","TWN":"怎麼樣？！那是我為了運動會特意找來的攻城戰車！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"지금 네 속도로 부딪치면 충격이 클 걸? 패배는 확정이지!","JPN":"今のあんたの速度でぶつかったら相当な衝撃をくらうだろうね！　これで負け確定よ！","ENG":"You'd better slow down if you don't want to get hurt. But either way, you lost!","TWN":"以妳現在的速度撞上去，衝擊可是相當大呢！妳輸定了！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"비장의 한 수인 것치고는 살짝 어설프네.","JPN":"切り札というにはちょっと惜しいかな。","ENG":"It's kind of sloppy for an ace up the sleeve.","TWN":"作為秘密武器，還欠點兒火候。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"미스틸테인! 기동!!","JPN":"ミスティルテイン！　起動！！","ENG":"Trigger Misteltein!","TWN":"米斯特丁！啟動！！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"......히이익!","JPN":"……ひいいっ！","ENG":"Heek!","TWN":"……（驚）咿！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"라이노를 한 방에 날려 버리다니! 저 선수...... 대단하잖아!","JPN":"ライノを一発で吹っ飛ばすなんて！　あの選手……すごい！","ENG":"She blew up the Rhino at once! She's... incredible!","TWN":"竟然一下就把犀牛打飛了！那個選手……太厲害了！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"STUDENT_EXTRA_B_TWINTAIL","text":{"KOREA":"하지만 덕분에 속도가 떨어졌어! 이대로라면 나이엘의 승리야!","JPN":"でもその影響でスピードが落ちた！　このままならナイエルが勝てる！","ENG":"But she had to slow down to do that. Naielle still wins!","TWN":"不過她的速度變慢了！這樣奈爾肯定會贏！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"GIRL_NPC_NULL_Q","text":{"KOREA":"......이, 이얏!","JPN":"……え、えいっ！","ENG":"E-eeyap!","TWN":"……咿，咿呀！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GIRL_NPC_NULL_Q","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_WIND2"},{"id":"L29_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"그래! 결국 먼저 골에 들어가는 건 나......!","JPN":"そう！　先にゴールインするのは私……！","ENG":"That's right! I'm still coming in first—","TWN":"是了！冠軍終究是我……！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"앗?! 뭐야, 이 깡통!?","JPN":"え！？　なに、この缶は！？","ENG":"Wah! What's this can doing here?","TWN":"啊？！什麼，這個飲料罐！？"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_SHIELD_SMALL"},{"id":"L34_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"아, 아야야......","JPN":"い、いててて……","ENG":"Ow, owww...","TWN":"啊，啊啊啊……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"......인정할 건 인정해야겠네.","JPN":"……これは認めるしかないわ。","ENG":"Okay, I'll give it to you.","TWN":"……妳的確不錯。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"확실히 아카데미 최강에 걸맞은 리액션이었어.","JPN":"確かにアカデミー最強の名に相応しい最強のリアクションだったわ。","ENG":"You're the Academy's best.","TWN":"對得起學院最強的名號。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"정말 그림같이 뒹굴더라?","JPN":"まるでアニメのワンシーンみたいね？","ENG":"Best at rolling on the ground, that is.","TWN":"現在真的像在揮灑一副畫似的滾來滾去呢？"},"stage":{"bg":"SKY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"이, 이건......","JPN":"こ、これは……","ENG":"Th-this...","TWN":"這，這……"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"이건 사기야! 대체 누가 여기에 음료수 캔을 가져다 둔 거냐고!","JPN":"これは罠よ！　いったい誰がこんなところに缶を置いたの！？","ENG":"This is rigged! Somebody left the soda can here on purpose!","TWN":"這是耍詐！究竟是誰把飲料罐放在這裡的！"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"과연 나이엘! 우린 알아! 평범한 승리로는 만족하지 못한다는 거지?","JPN":"さすがナイエル！　俺たちは知っている！　普通の勝利じゃ満足できないってことだな？","ENG":"You never disappoint us, Naielle! We get it. You just can't be satisfied by winning like everyone else, can you?","TWN":"不愧是奈爾！我們知道！平凡的勝利是無法滿足妳的？"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"STUDENT_EXTRA_B_TWINTAIL","text":{"KOREA":"당연하지! 일부러 자기를 궁지로 몰아 넣었다가 희망에 찬 상대를 단숨에 부숴 버릴 계획일 거야!","JPN":"当たり前さ！　わざと自分を窮地に追い込んで、希望に満ちた敵を一気に挫折させる計画だ！","ENG":"No, she can't. She's driving herself to a corner, just so she can give hope to her enemy, and then take it away right before her eyes!","TWN":"那是當然！她一定是故意把自己逼入絕境，然後再給滿懷希望的對手致命一擊的！"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"STUDENT_EXTRA_B_TWINTAIL","text":{"KOREA":"역시 우리 <color=#ffd34c>아이언 스틸</color>의 대장에 걸맞는 잔혹함......! 무시무시해......!","JPN":"さすが我が<color=#ffd34c>アイアンスチール</color>の隊長らしい残酷さ……！　恐るべし……！","ENG":"There's a reason she's the leader of us <color=#ffd34c>Iron Steel</color>. She's so ruthless!","TWN":"不愧是我們<color=#ffd34c>鋼鐵</color>的隊長……！夠殘忍、夠冷血……！"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"......어라?","JPN":"……あれ？","ENG":"Err?","TWN":"……咦？"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"선수들한테 나눠 줄 음료수가 하나 비는데? 어디 갔지?","JPN":"選手たちに配る飲み物が1個足りない！　どこに消えたんだろう？","ENG":"I seem to be missing one soda can from my stash. Where did it go?","TWN":"要發給選手們的飲料怎麼少了一個？放哪裡了？"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"GIRL_NPC_NULL_Q","text":{"KOREA":"......말도 없이 빌려가서 죄송해요.","JPN":"……何も言わずに借りてごめんなさい。","ENG":"I'm sorry I borrowed it without telling you.","TWN":"……對不起，我擅自借用了一下。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"GIRL_NPC_NULL_Q","text":{"KOREA":"여기 가져다 놓을게요.","JPN":"ここに戻しておくね。","ENG":"I've brought it back.","TWN":"我這就去拿回來。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"아! 찾았다!","JPN":"あ！　見つけた！","ENG":"Ah, there it is!","TWN":"啊！找到了！"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"으...... 근데 그새 누가 밟고 갔나 보네. 캔이 다 찌그러졌어.","JPN":"うーん……でも誰かに踏まれたのかな。缶が潰れているわ。","ENG":"Ack, but who stepped on it? It's all crushed.","TWN":"呃……不過好像被誰給踩了，飲料罐都變形了。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"할 수 없네. 그냥 새로 하나 더 가져와야겠다.","JPN":"仕方ないわね。新しいものを持ってこよう。","ENG":"Oh well, I'm just going to get a new one.","TWN":"沒辦法了，只能再去拿一個新的了。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_BLUE","text":{"KOREA":"저어...... 임시 편입생 언니......","JPN":"あの……臨時編入生のお姉さん……","ENG":"Erm... hey...","TWN":"那個……臨時插班生姐姐……"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_BLUE","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"응? 나 불렀어?","JPN":"うん？　私を呼んだ？","ENG":"Hm? Did you call me?","TWN":"嗯？你是在叫我嗎？"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_BLUE","text":{"KOREA":"앗, 네......","JPN":"あっ、はい……","ENG":"Ah, yes...","TWN":"啊，是……"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_BLUE","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SPEAKER_JUNIOR_NULL_BLUE","face":"UNIT_LAUGH"}}}},{"id":"L20_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_BLUE","text":{"KOREA":"방금 경기, 정말 대단했어요. 저...... 그런 건 처음 봤거든요.","JPN":"さっきの試合、本当にすごかったです。あの……あんなの初めてみました。","ENG":"That was incredible, what you did in the game. I... I've never seen anything like it.","TWN":"剛剛的比賽，你實在太厲害了。我……還是第一次看到那樣的技能。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_BLUE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SPEAKER_JUNIOR_NULL_BLUE","face":"UNIT_LAUGH"}}}},{"id":"L21_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_BLUE","text":{"KOREA":"나도 마찬가지야!","JPN":"同じく！","ENG":"Same here!","TWN":"我也是！"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_BLUE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SPEAKER_JUNIOR_NULL_BLUE","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_BLUE","text":{"KOREA":"아무리 카운터라지만 그렇게 빨리 달리면서 동시에 염력까지 쓸 수 있다니......","JPN":"いくらカウンターとはいえ、あんなに速く走りながら同時に念動力まで使えるなんて……","ENG":"I've never seen any other Counter run that fast and use telekinesis at the same time.","TWN":"即使是制裁者，快速奔跑的情況下居然還能使用念力……"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_BLUE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SPEAKER_JUNIOR_NULL_BLUE","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_BLUE","text":{"KOREA":"좀 더 언니를 가까이서 관찰하고 싶어! 우리 히어로 동아리에 입부하지 않을래?","JPN":"もっとお姉さんを近くで観察してみたい！　うちのヒーローサークルに入部しない？","ENG":"I'd love to watch you more closely! How'd you like to join our club, the Special Hero Class?","TWN":"我想近距離觀察姐姐！你願意加入我們英雄社團嗎？"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_BLUE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SPEAKER_JUNIOR_NULL_BLUE","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"......후훗, 호기심 많은 꼬마 과학자구나?","JPN":"……フフッ、好奇心旺盛なちびっ子科学者なんだね。","ENG":"Hah hah, you're a curious little scientist, aren't you?","TWN":"……呵呵，原來是充滿好奇心的小科學家啊？"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"하지만 아쉽게도 난 정식 편입생이 아니라 입부하긴 어렵겠어.","JPN":"残念だけど、私は正式な編入生じゃないから入部は難しそう。","ENG":"But I'm sorry. I can't join your club because I'm not a regular transfer student.","TWN":"不過很可惜，我不是正式插班生，不能加入你們社團。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_BLUE","text":{"KOREA":"그래......? 힝......","JPN":"そうなの……？　ひーん……","ENG":"You can't? Hnnggg...","TWN":"是嗎……？嗯……"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_BLUE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_JUNIOR_NULL_BLUE","face":"UNIT_DESPAIR"}}}},{"id":"L31_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"그렇게 실망하진 마.","JPN":"でもあまりガッカリしないでね。","ENG":"Don't be so disappointed.","TWN":"不用那麼失望。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"내가 아니라도 조만간 나보다 더 대단한 친구가 입학하게 될 테니까.","JPN":"近いうちに、私よりもっとすごい友達が編入してくるから。","ENG":"Soon, someone even more amazing than me will join your school.","TWN":"我雖然不能加入，但用不了多久，就會有個比我更厲害的人入學哦。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"그 때는 잘 부탁할게?","JPN":"その時はよろしくね。","ENG":"Please take good care of her, okay?","TWN":"到時就拜託你們了！"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_LAUGH"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_BLUE","text":{"KOREA":"더 대단하다고......? 그럼 그 사람은 A급 카운터야?","JPN":"もっとすごい……？　じゃあその人はA級カウンターなの？","ENG":"More amazing than you? Is she a Grade A Counter, then?","TWN":"更厲害……？那個人是A級制裁者嗎？"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_BLUE","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SPEAKER_JUNIOR_NULL_BLUE","face":"UNIT_SURPRISE"}}}},{"id":"L38_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"뭐, 그 친구는 자길 C급이라고 소개하겠지만. 그대로 믿지 않는 편이 좋을 거야.","JPN":"まあ、あの人なら自分のことをC級って言いそうだけど。信じなくていいよ。","ENG":"Well, she'll probably say she's Grade C. But you shouldn't believe her.","TWN":"算是吧，雖然她對外自稱是C級，但最好不要完全相信她的話。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"원래 진짜 강한 사람은 자기 본 실력을 숨기는 법이잖아?","JPN":"本当に強い人は、自分の真の実力を隠すものでしょ？","ENG":"People who are really strong rarely show what they're capable of.","TWN":"真正的強者向來都會隱藏自己的真正實力不是嗎？"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_BLUE","text":{"KOREA":"오오! 본 실력을 숨기는 카운터라니!! 완전 히어로스러워!","JPN":"おおー！　真の力を隠すカウンターだなんて！！　本物のヒーローっぽい！","ENG":"Ooo! A Counter who hides what she can do! Sounds like a real hero!","TWN":"噢噢！隱藏真正實力的制裁者！聽起來就很英雄！"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_BLUE","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SPEAKER_JUNIOR_NULL_BLUE","face":"UNIT_LAUGH"}}}},{"id":"L43_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_BLUE","text":{"KOREA":"맡겨 둬! 그 사람을 관찰할 때는 정체가 안 들키게 조심할게!","JPN":"任せておいて！　その人を観察する時は、正体がバレないように気をつけるよ！","ENG":"Count on me. I'll make sure she doesn't know I'm watching her!","TWN":"交給我吧！觀察那個人時，我一定小心不讓她發現！"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_BLUE","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SPEAKER_JUNIOR_NULL_BLUE","face":"UNIT_PRIDE"}}}},{"id":"L45_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"후훗. 재밌겠네. 벌써부터 관찰 결과가 궁금해지는데?","JPN":"フフッ、面白そうね。観察結果が楽しみだわ。","ENG":"Hah hah. That sounds like fun. I can't wait to see what you might find out about her.","TWN":"呵呵，有意思。我已經想知道觀察結果了呢！"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_BLUE","text":{"KOREA":"저기, 아르티......","JPN":"あの、アルティ……","ENG":"Hey, Arti...","TWN":"那個，阿爾蒂……"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_BLUE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SPEAKER_JUNIOR_NULL_BLUE","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_BLUE","text":{"KOREA":"응? ......아 참!","JPN":"うん？　……あ、そうだ！","ENG":"Huh? Oh, right!","TWN":"嗯？……啊對了！"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_BLUE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SPEAKER_JUNIOR_NULL_BLUE","face":"UNIT_SURPRISE"}}}},{"id":"L50_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_BLUE","text":{"KOREA":"실력자 언니! 실은 우리가 하나 물어보고 싶은 게 있어서 찾아왔어!","JPN":"実力者のお姉さん！　実はぼくたち、一つ聞きたいことがあるんだ！","ENG":"Miss Amazing, we actually came to ask you something.","TWN":"實力派姐姐！其實我們過來是想問你一個問題！"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_BLUE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SPEAKER_JUNIOR_NULL_BLUE","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"그래? 뭐가 궁금한데?","JPN":"そうなの？　何かしら？","ENG":"Okay, what is it?","TWN":"是嗎？你們想問什麼？"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_BLUE","text":{"KOREA":"혹시...... 스카이라는 초등학생 아이를 기억하시나요?","JPN":"あの……スカイという初等部の子を覚えていますか？","ENG":"Do you by any chance... remember the elementary school student named Sky?","TWN":"那個……你記得一個叫絲凱的小學生嗎？"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_BLUE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SPEAKER_JUNIOR_NULL_BLUE","face":"UNIT_PRIDE"}}}},{"id":"L6_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_BLUE","text":{"KOREA":"청팀 선수였는데...... 이전 경기에서 엄청 활약했거든요......!","JPN":"青組の選手なんですけど……前の試合で大活躍したんです……！","ENG":"She's on the Blue Team... And she really shone in the previous game!","TWN":"她是藍隊的選手……在之前的比賽中表現得非常亮眼……！"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_BLUE","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SPEAKER_JUNIOR_NULL_BLUE","face":"UNIT_PRIDE"}}}},{"id":"L7_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_BLUE","text":{"KOREA":"꼬리잡기에서 점수도...... 많이 받았고요.","JPN":"しっぽ取りゲームで点数も……かなり多く取りました。","ENG":"She earned lots of points in the Catch the Tail game, too.","TWN":"在抓尾巴比賽中也拿到了……很高的分數。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_BLUE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SPEAKER_JUNIOR_NULL_BLUE","face":"UNIT_PRIDE"}}}},{"id":"L9_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"스카이......?","JPN":"スカイ……？","ENG":"Sky?","TWN":"絲凱……？"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"글쎄. 초등학생이 그 정도 활약을 했다면 기억이 날 것 같은데, 잘 모르겠네.","JPN":"さあ、初等部の子がそんなに活躍しているなら覚えているはずだけど。わからないな。","ENG":"I don't know. I don't think I noticed an elementary school student in either game.","TWN":"嗯，小學生那麼厲害的話我應該記得才是，可我沒什麼印象呢。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"혹시 네 이름이 스카이야? 못 알아본 거라면 미안해.","JPN":"もしかしてあなたの名前がスカイなの？　気づいてなかったならごめんね。","ENG":"Is your name Sky? I'm sorry I didn't recognize you.","TWN":"難道你就是絲凱？是的話很抱歉沒能認出你。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_BLUE","text":{"KOREA":"아, 아뇨! 스카이는...... 그러니까......!","JPN":"い、いいえ！　スカイは……えっと……！","ENG":"Oh, no. Sky is... She's... erm...","TWN":"不，不是的！絲凱是……那個……！"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_BLUE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SPEAKER_JUNIOR_NULL_BLUE","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_BLUE","text":{"KOREA":"아냐, 아냐! 별거 아닌 일로 실례했어!","JPN":"あ、もういいよ！　そんなに大事なことじゃないから。ごめんね！","ENG":"No, no! Never mind! We're sorry we bothered you!","TWN":"不是，不是！沒什麼啦！"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_BLUE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SPEAKER_JUNIOR_NULL_BLUE","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_BLUE","text":{"KOREA":"우린 이만 가볼게, 언니! 질문에 응답해 줘서 고마워!","JPN":"ぼくたちもう帰るね、お姉さん！　質問に答えてくれてありがとう！","ENG":"We've got to go now. Thank you for answering our question!","TWN":"我們走了，姐姐！謝謝你回答我們的問題！"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_BLUE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SPEAKER_JUNIOR_NULL_BLUE","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"......왜 저러지?","JPN":"……どうしたんだろう？","ENG":"Did I say something wrong?","TWN":"……怎麼回事？"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"방금 뭔가...... 굉장히 아쉬워하는 것 같았는데.","JPN":"なんだか……すごく残念そうな雰囲気だったな。","ENG":"For a moment, they looked very disappointed.","TWN":"剛剛……她們好像很遺憾的感覺呢。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":null,"text":{"KOREA":"<b>제 3 경기 - 개인 전투 경기</b>","JPN":"<b>第三試合 - 個人戦</b>","ENG":"<b>Round 3: Individual Combat</b>","TWN":"<b>第三場比賽 - 個人賽</b>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_TADA2"}]`);export{e as default};